# ── Layouts ─────────────────────────────────────────────────────
cat > app/src/main/res/layout/activity_settings.xml << 'EOF'
<?xml version="1.0" encoding="utf-8"?>
<androidx.coordinatorlayout.widget.CoordinatorLayout xmlns:android="http://schemas.android.com/apk/res/android"
    xmlns:app="http://schemas.android.com/apk/res-auto"
    android:layout_width="match_parent" android:layout_height="match_parent"
    android:background="@color/background">
    <com.google.android.material.appbar.AppBarLayout android:layout_width="match_parent"
        android:layout_height="wrap_content" android:theme="@style/ThemeOverlay.MikasaIG.AppBar">
        <com.google.android.material.appbar.MaterialToolbar android:id="@+id/toolbar"
            android:layout_width="match_parent" android:layout_height="?attr/actionBarSize"
            app:title="Settings" app:titleTextColor="@color/text_primary"
            app:navigationIconTint="@color/on_primary"/>
    </com.google.android.material.appbar.AppBarLayout>
    <ScrollView android:layout_width="match_parent" android:layout_height="match_parent"
        app:layout_behavior="@string/appbar_scrolling_view_behavior">
        <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
            android:orientation="vertical" android:padding="16dp">

            <!-- Auto Fill Card -->
            <com.google.android.material.card.MaterialCardView android:layout_width="match_parent"
                android:layout_height="wrap_content" android:layout_marginBottom="12dp"
                app:cardBackgroundColor="@color/card_bg" app:cardCornerRadius="12dp"
                app:strokeColor="@color/neon_blue" app:strokeWidth="1dp">
                <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                    android:orientation="vertical" android:padding="16dp">
                    <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                        android:text="⚡ Auto Fill" android:textColor="@color/neon_blue"
                        android:textSize="14sp" android:textStyle="bold" android:layout_marginBottom="12dp"/>
                    <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:orientation="horizontal" android:gravity="center_vertical"
                        android:layout_marginBottom="12dp">
                        <LinearLayout android:layout_width="0dp" android:layout_height="wrap_content"
                            android:layout_weight="1" android:orientation="vertical">
                            <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                                android:text="Enable Auto Fill" android:textColor="@color/text_primary" android:textSize="15sp"/>
                            <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                                android:text="Isi form otomatis saat halaman dimuat"
                                android:textColor="@color/text_secondary" android:textSize="12sp"/>
                        </LinearLayout>
                        <com.google.android.material.switchmaterial.SwitchMaterial
                            android:id="@+id/switchAutoFill" android:layout_width="wrap_content"
                            android:layout_height="wrap_content"/>
                    </LinearLayout>
                    <com.google.android.material.textfield.TextInputLayout android:id="@+id/tilFillName"
                        style="@style/Widget.Material3.TextInputLayout.OutlinedBox"
                        android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:layout_marginBottom="8dp" android:hint="Nama (kosongkan = random)">
                        <com.google.android.material.textfield.TextInputEditText android:id="@+id/etFillName"
                            android:layout_width="match_parent" android:layout_height="wrap_content"
                            android:textColor="@color/input_text" android:inputType="textPersonName"/>
                    </com.google.android.material.textfield.TextInputLayout>
                    <com.google.android.material.textfield.TextInputLayout android:id="@+id/tilFillUsername"
                        style="@style/Widget.Material3.TextInputLayout.OutlinedBox"
                        android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:layout_marginBottom="8dp" android:hint="Username (kosongkan = random)">
                        <com.google.android.material.textfield.TextInputEditText android:id="@+id/etFillUsername"
                            android:layout_width="match_parent" android:layout_height="wrap_content"
                            android:textColor="@color/input_text" android:inputType="text"/>
                    </com.google.android.material.textfield.TextInputLayout>
                    <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:orientation="horizontal" android:layout_marginBottom="8dp">
                        <com.google.android.material.textfield.TextInputLayout
                            style="@style/Widget.Material3.TextInputLayout.OutlinedBox"
                            android:layout_width="0dp" android:layout_height="wrap_content"
                            android:layout_weight="1" android:layout_marginEnd="8dp"
                            android:hint="Umur Min">
                            <com.google.android.material.textfield.TextInputEditText android:id="@+id/etAgeMin"
                                android:layout_width="match_parent" android:layout_height="wrap_content"
                                android:textColor="@color/input_text" android:inputType="number" android:text="20"/>
                        </com.google.android.material.textfield.TextInputLayout>
                        <com.google.android.material.textfield.TextInputLayout
                            style="@style/Widget.Material3.TextInputLayout.OutlinedBox"
                            android:layout_width="0dp" android:layout_height="wrap_content"
                            android:layout_weight="1" android:hint="Umur Max">
                            <com.google.android.material.textfield.TextInputEditText android:id="@+id/etAgeMax"
                                android:layout_width="match_parent" android:layout_height="wrap_content"
                                android:textColor="@color/input_text" android:inputType="number" android:text="49"/>
                        </com.google.android.material.textfield.TextInputLayout>
                    </LinearLayout>
                </LinearLayout>
            </com.google.android.material.card.MaterialCardView>

            <!-- Password Autofill Card -->
            <com.google.android.material.card.MaterialCardView android:layout_width="match_parent"
                android:layout_height="wrap_content" android:layout_marginBottom="12dp"
                app:cardBackgroundColor="@color/card_bg" app:cardCornerRadius="12dp"
                app:strokeColor="@color/divider" app:strokeWidth="1dp">
                <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                    android:orientation="vertical" android:padding="16dp">
                    <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                        android:text="🔑 Password Autofill" android:textColor="@color/neon_blue"
                        android:textSize="14sp" android:textStyle="bold" android:layout_marginBottom="12dp"/>
                    <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:orientation="horizontal" android:gravity="center_vertical"
                        android:layout_marginBottom="12dp">
                        <LinearLayout android:layout_width="0dp" android:layout_height="wrap_content"
                            android:layout_weight="1" android:orientation="vertical">
                            <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                                android:text="Enable Password Autofill" android:textColor="@color/text_primary" android:textSize="15sp"/>
                            <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                                android:text="Isi password otomatis pada form login"
                                android:textColor="@color/text_secondary" android:textSize="12sp"/>
                        </LinearLayout>
                        <com.google.android.material.switchmaterial.SwitchMaterial
                            android:id="@+id/switchPasswordAutofill" android:layout_width="wrap_content"
                            android:layout_height="wrap_content"/>
                    </LinearLayout>
                    <com.google.android.material.textfield.TextInputLayout android:id="@+id/tilDefaultPassword"
                        style="@style/Widget.Material3.TextInputLayout.OutlinedBox"
                        android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:hint="Default Password" app:endIconMode="password_toggle">
                        <com.google.android.material.textfield.TextInputEditText android:id="@+id/etDefaultPassword"
                            android:layout_width="match_parent" android:layout_height="wrap_content"
                            android:textColor="@color/input_text" android:inputType="textPassword"/>
                    </com.google.android.material.textfield.TextInputLayout>
                </LinearLayout>
            </com.google.android.material.card.MaterialCardView>

            <!-- Auto Profile Card -->
            <com.google.android.material.card.MaterialCardView android:layout_width="match_parent"
                android:layout_height="wrap_content" android:layout_marginBottom="12dp"
                app:cardBackgroundColor="@color/card_bg" app:cardCornerRadius="12dp"
                app:strokeColor="@color/divider" app:strokeWidth="1dp">
                <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                    android:orientation="vertical" android:padding="16dp">
                    <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                        android:text="🖼 Random Profile Picture" android:textColor="@color/neon_blue"
                        android:textSize="14sp" android:textStyle="bold" android:layout_marginBottom="12dp"/>
                    <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:orientation="horizontal" android:gravity="center_vertical"
                        android:layout_marginBottom="12dp">
                        <LinearLayout android:layout_width="0dp" android:layout_height="wrap_content"
                            android:layout_weight="1" android:orientation="vertical">
                            <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                                android:text="Enable Random Profile Picture"
                                android:textColor="@color/text_primary" android:textSize="15sp"/>
                            <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                                android:text="Pilih foto random dari daftar"
                                android:textColor="@color/text_secondary" android:textSize="12sp"/>
                        </LinearLayout>
                        <com.google.android.material.switchmaterial.SwitchMaterial
                            android:id="@+id/switchAutoProfile" android:layout_width="wrap_content"
                            android:layout_height="wrap_content"/>
                    </LinearLayout>
                    <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:orientation="horizontal">
                        <com.google.android.material.button.MaterialButton android:id="@+id/btnAddPhoto"
                            style="@style/Widget.Material3.Button.OutlinedButton"
                            android:layout_width="0dp" android:layout_height="wrap_content"
                            android:layout_weight="1" android:layout_marginEnd="8dp"
                            android:textColor="@color/btn_text" android:text="+ Tambah Foto"/>
                        <com.google.android.material.button.MaterialButton android:id="@+id/btnViewPhotos"
                            style="@style/Widget.Material3.Button.OutlinedButton"
                            android:layout_width="0dp" android:layout_height="wrap_content"
                            android:layout_weight="1" android:textColor="@color/btn_text"
                            android:text="Lihat Daftar"/>
                    </LinearLayout>
                    <TextView android:id="@+id/tvPhotoCount"
                        android:layout_width="wrap_content" android:layout_height="wrap_content"
                        android:text="0 foto tersimpan" android:textColor="@color/text_secondary"
                        android:textSize="12sp" android:layout_marginTop="8dp"/>
                </LinearLayout>
            </com.google.android.material.card.MaterialCardView>

            <!-- Authenticator Card -->
            <com.google.android.material.card.MaterialCardView android:layout_width="match_parent"
                android:layout_height="wrap_content" android:layout_marginBottom="12dp"
                app:cardBackgroundColor="@color/card_bg" app:cardCornerRadius="12dp"
                app:strokeColor="@color/divider" app:strokeWidth="1dp">
                <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                    android:orientation="vertical" android:padding="16dp">
                    <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                        android:text="🔐 Authenticator" android:textColor="@color/neon_blue"
                        android:textSize="14sp" android:textStyle="bold" android:layout_marginBottom="8dp"/>
                    <com.google.android.material.button.MaterialButton android:id="@+id/btnOpenAuthenticator"
                        style="@style/Widget.Material3.Button.OutlinedButton"
                        android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:textColor="@color/btn_text" android:text="Kelola Authenticator Accounts"/>
                </LinearLayout>
            </com.google.android.material.card.MaterialCardView>

            <!-- Clear Data Card -->
            <com.google.android.material.card.MaterialCardView android:layout_width="match_parent"
                android:layout_height="wrap_content" android:layout_marginBottom="12dp"
                app:cardBackgroundColor="@color/card_bg" app:cardCornerRadius="12dp"
                app:strokeColor="@color/divider" app:strokeWidth="1dp">
                <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                    android:orientation="vertical" android:padding="16dp">
                    <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                        android:text="🗑 Clear Data" android:textColor="@color/neon_blue"
                        android:textSize="14sp" android:textStyle="bold" android:layout_marginBottom="8dp"/>
                    <com.google.android.material.button.MaterialButton android:id="@+id/btnClearCookies"
                        style="@style/Widget.Material3.Button.OutlinedButton"
                        android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:layout_marginBottom="8dp" android:textColor="@color/btn_text" android:text="🍪 Clear Cookies"/>
                    <com.google.android.material.button.MaterialButton android:id="@+id/btnClearCache"
                        style="@style/Widget.Material3.Button.OutlinedButton"
                        android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:layout_marginBottom="8dp" android:textColor="@color/btn_text" android:text="🗂 Clear Cache"/>
                    <com.google.android.material.button.MaterialButton android:id="@+id/btnClearSession"
                        style="@style/Widget.Material3.Button.OutlinedButton"
                        android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:textColor="@color/btn_text" android:text="🔒 Clear Session"/>
                </LinearLayout>
            </com.google.android.material.card.MaterialCardView>

            <com.google.android.material.button.MaterialButton android:id="@+id/btnSaveSettings"
                android:layout_width="match_parent" android:layout_height="wrap_content"
                android:layout_marginTop="8dp" android:text="💾 Simpan Settings"
                android:textColor="@color/white"/>
        </LinearLayout>
    </ScrollView>
</androidx.coordinatorlayout.widget.CoordinatorLayout>
EOF

cat > app/src/main/res/layout/activity_authenticator.xml << 'EOF'
<?xml version="1.0" encoding="utf-8"?>
<androidx.coordinatorlayout.widget.CoordinatorLayout xmlns:android="http://schemas.android.com/apk/res/android"
    xmlns:app="http://schemas.android.com/apk/res-auto"
    android:layout_width="match_parent" android:layout_height="match_parent"
    android:background="@color/background">
    <com.google.android.material.appbar.AppBarLayout android:layout_width="match_parent"
        android:layout_height="wrap_content" android:theme="@style/ThemeOverlay.MikasaIG.AppBar">
        <com.google.android.material.appbar.MaterialToolbar android:id="@+id/toolbar"
            android:layout_width="match_parent" android:layout_height="?attr/actionBarSize"
            app:title="Authenticator" app:titleTextColor="@color/text_primary"
            app:navigationIconTint="@color/on_primary"/>
    </com.google.android.material.appbar.AppBarLayout>
    <LinearLayout android:layout_width="match_parent" android:layout_height="match_parent"
        android:orientation="vertical" app:layout_behavior="@string/appbar_scrolling_view_behavior">
        <com.google.android.material.card.MaterialCardView android:layout_width="match_parent"
            android:layout_height="wrap_content" android:layout_margin="8dp"
            app:cardBackgroundColor="@color/card_bg" app:cardCornerRadius="12dp"
            app:strokeColor="@color/neon_blue" app:strokeWidth="1dp">
            <LinearLayout android:layout_width="match_parent" android:layout_height="wrap_content"
                android:orientation="vertical" android:padding="12dp">
                <TextView android:layout_width="wrap_content" android:layout_height="wrap_content"
                    android:text="⚡ Quick OTP — Paste Secret Key"
                    android:textColor="@color/neon_blue" android:textSize="13sp"
                    android:textStyle="bold" android:layout_marginBottom="8dp"/>
                <com.google.android.material.textfield.TextInputLayout
                    style="@style/Widget.Material3.TextInputLayout.OutlinedBox"
                    android:layout_width="match_parent" android:layout_height="wrap_content"
                    android:layout_marginBottom="8dp" android:hint="Paste Secret Key di sini">
                    <com.google.android.material.textfield.TextInputEditText android:id="@+id/etQuickSecret"
                        android:layout_width="match_parent" android:layout_height="wrap_content"
                        android:textColor="@color/input_text" android:fontFamily="monospace"
                        android:inputType="textVisiblePassword"/>
                </com.google.android.material.textfield.TextInputLayout>
                <com.google.android.material.button.MaterialButton android:id="@+id/btnQuickGenerate"
                    android:layout_width="match_parent" android:layout_height="wrap_content"
                    android:text="🔑 Generate OTP &amp; Auto Copy"
                    android:textColor="@color/white"/>
                <TextView android:id="@+id/tvQuickOtp"
                    android:layout_width="match_parent" android:layout_height="wrap_content"
                    android:gravity="center" android:text="" android:textColor="@color/totp_green"
                    android:textSize="36sp" android:textStyle="bold" android:letterSpacing="0.2"
                    android:fontFamily="monospace" android:layout_marginTop="8dp"
                    android:visibility="gone"/>
            </LinearLayout>
        </com.google.android.material.card.MaterialCardView>
        <TextView android:id="@+id/tvEmpty" android:layout_width="match_parent"
            android:layout_height="0dp" android:layout_weight="1" android:gravity="center"
            android:text="@string/authenticator_empty" android:textColor="@color/text_secondary"
            android:textSize="15sp" android:visibility="gone" android:padding="32dp"/>
        <androidx.recyclerview.widget.RecyclerView android:id="@+id/recyclerView"
            android:layout_width="match_parent" android:layout_height="0dp"
            android:layout_weight="1" android:padding="8dp" android:clipToPadding="false"/>
    </LinearLayout>
    <com.google.android.material.floatingactionbutton.FloatingActionButton android:id="@+id/fabAdd"
        android:layout_width="wrap_content" android:layout_height="wrap_content"
        android:layout_gravity="bottom|end" android:layout_margin="16dp"
        android:contentDescription="Add" app:srcCompat="@drawable/ic_add" app:tint="@color/white"/>
</androidx.coordinatorlayout.widget.CoordinatorLayout>
EOF

